CustomField.formula:
if(Erbbauzins__c == NULL, 
			if(OeffentlicherStatus__c == 'Verkauft', 
						Monthly_Rent__c *12 /beurkundeter_Kaufpreis__c,
						Monthly_Rent__c *12 /Purchase_Price__c 
						), 
			if(OeffentlicherStatus__c == 'Verkauft', 
						(Monthly_Rent__c *12-Erbauzins_Monat__c*12) /beurkundeter_Kaufpreis__c,
						(Monthly_Rent__c *12-Erbauzins_Monat__c*12) /Purchase_Price__c 
						)
		)
